+use std::collections::BTreeMap;
+
+#[cfg(feature = "diagram")]
+fn dummy_span() -> Span {
+    Span {
+        start: Position {
+            line: 1,
+            col: 1,
+            byte: 0,
+        },
+        end: Position {
+            line: 1,
+            col: 1,
+            byte: 0,
+        },
+    }
+}
+
+#[cfg(feature = "diagram")]
+fn make_ir(
+    node_labels: &[&str],
+    edges: &[(usize, usize)],
+    direction: GraphDirection,
+) -> MermaidDiagramIr {
+    let nodes: Vec<IrNode> = node_labels
+        .iter()
+        .map(|label| IrNode {
+            id: label.to_string(),
+            label: None,
+            shape: NodeShape::Rect,
+            classes: Vec::new(),
+            style_ref: None,
+            span_primary: dummy_span(),
+            span_all: Vec::new(),
+            implicit: false,
+            members: Vec::new(),
+        })
+        .collect();
+
+    let ir_edges: Vec<IrEdge> = edges
+        .iter()
+        .map(|&(from, to)| IrEdge {
+            from: IrEndpoint::Node(IrNodeId(from)),
+            to: IrEndpoint::Node(IrNodeId(to)),
+            arrow: "-->".to_string(),
+            label: None,
+            style_ref: None,
+            span: dummy_span(),
+        })
+        .collect();
+
+    MermaidDiagramIr {
+        diagram_type: DiagramType::Graph,
+        direction,
+        nodes,
+        edges: ir_edges,
+        ports: Vec::new(),
+        clusters: Vec::new(),
+        labels: Vec::new(),
+        pie_entries: Vec::new(),
+        pie_title: None,
+        pie_show_data: false,
+        style_refs: Vec::new(),
+        links: Vec::new(),
+        meta: MermaidDiagramMeta {
+            diagram_type: DiagramType::Graph,
+            direction,
+            support_level: MermaidSupportLevel::Supported,
+            init: MermaidInitParse {
+                config: MermaidInitConfig {
+                    theme: None,
+                    theme_variables: BTreeMap::new(),
+                    flowchart_direction: None,
+                },
+                warnings: Vec::new(),
+                errors: Vec::new(),
+            },
+            theme_overrides: MermaidThemeOverrides {
+                theme: None,
+                theme_variables: BTreeMap::new(),
+            },
+            guard: MermaidGuardReport::default(),
+        },
+    }
+}
