+    while li < left.len() && ri < right.len() {
+        if left[li] <= right[ri] {
+            seq[wi] = left[li];
+            li += 1;
+        } else {
+            count += left.len() - li;
+            seq[wi] = right[ri];
+            ri += 1;
+        }
+        wi += 1;
+    }
+    while li < left.len() {
+        seq[wi] = left[li];
+        li += 1;
+        wi += 1;
+    }
+    while ri < right.len() {
+        seq[wi] = right[ri];
+        ri += 1;
+        wi += 1;
+    }
+    count
